PART = '        edit_bones.remove(bone)\n\n    def bone(name, head, tail, parent=None, connected=False):\n        item = edit_bones.new(name)\n        item.head = head\n        item.tail = tail\n        if parent:\n            item.parent = edit_bones[parent]\n            item.use_connect = connected\n        return item\n\n    bone("root", (0.0, 0.0, 0.05), (0.0, 0.0, 0.35))\n    bone("pelvis", (0.0, 0.0, 0.55), (0.0, 0.0, 0.95), "root")\n    bone("spine", (0.0, 0.0, 0.9), (0.0, 0.0, 1.35), "pelvis")\n    bone("chest", (0.0, 0.0, 1.28), (0.0, 0.0, 1.67), "spine")\n    bone("neck", (0.0, 0.0, 1.58), (0.0, 0.0, 1.82), "chest")\n    bone("head", (0.0, 0.0, 1.76), (0.0, 0.0, 2.35), "neck")\n    bone("jaw", (0.0, -0.22, 1.83), (0.0, -0.53, 1.70), "head")\n    bone("ear.L", (-0.27, 0.0, 2.22), (-0.35, 0.0, 2.55), "head")\n    bone("ear.R", (0.27, 0.0, 2.22), (0.35, 0.0, 2.55), "head")\n    bone("eye.L", (-0.20, -0.30, 2.00), (-0.20, -0.52, 2.00), "head")\n    bone("eye.R", (0.20, -0.30, 2.00), (0.20, -0.52, 2.00), "head")\n\n    for suffix, sign in (("L", -1.0), ("R", 1.0)):\n        bone(\n            f"upper_arm.{suffix}",\n            (0.40 * sign, 0.0, 1.48),\n            (0.68 * sign, -0.02, 1.12),\n            "chest",\n        )\n        bone(\n            f"forearm.{suffix}",\n            (0.68 * sign, -0.02, 1.12),\n            (0.74 * sign, -0.08, 0.78),\n            f"upper_arm.{suffix}",\n            True,\n        )\n        bone(\n            f"hand.{suffix}",\n            (0.74 * sign, -0.08, 0.78),\n            (0.76 * sign, -0.18, 0.55),\n            f"forearm.{suffix}",\n            True,\n        )\n        bone(\n            f"thigh.{suffix}",\n            (0.25 * sign, 0.0, 0.82),\n            (0.28 * sign, 0.0, 0.46),\n            "pelvis",\n        )\n        bone(\n            f"shin.{suffix}",\n            (0.28 * sign, 0.0, 0.46),\n            (0.28 * sign, -0.03, 0.17),\n            f"thigh.{suffix}",\n            True,\n        )\n        bone(\n            f"foot.{suffix}",\n            (0.28 * sign, -0.03, 0.17),\n            (0.28 * sign, -0.38, 0.08),\n            f"shin.{suffix}",\n            True,\n        )\n\n    tail_points = [\n        (0.44, 0.10, 0.83),\n        (0.70, 0.18, 1.00),\n        (0.94, 0.22, 1.15),\n        (1.18, 0.18, 1.20),\n        (1.39, 0.10, 1.12),\n        (1.56, 0.02, 0.98),\n    ]\n    for index in range(5):\n        name = f"tail.{index + 1:02d}"\n        parent = "pelvis" if index == 0 else f"tail.{index:02d}"\n        bone(name, tail_points[index], tail_points[index + 1], parent, index > 0)\n\n    bpy.ops.object.mode_set(mode="POSE")\n    for pose_bone in rig.pose.bones:\n        pose_bone.rotation_mode = "XYZ"\n    bpy.ops.object.mode_set(mode="OBJECT")\n    return rig, tail_points\n\n\ndef create_oyen_purba(rig, tail_points):\n    orange = make_material("Blaze Orange", rgba("#E8842A"), 0.72)\n    cream = make_material("Sun Cream", rgba("#F7D89B"), 0.68)\n    cocoa = make_material("Deep Cocoa", rgba("#4A2C24"), 0.58)\n    amber = make_material("Amber Eyes", rgba("#D79223"), 0.32)\n    white = make_material("Eye White", rgba("#FFF4D8"), 0.38)\n    pink = make_material("Nose Pink", rgba("#C96A62"), 0.48)\n    cloth = make_material("Purba Cloth", rgba("#A95F20"), 0.78)\n    tooth = make_material("Fang Ivory", rgba("#FFF0C9"), 0.45)\n    leaf = make_material("Leaf Tail Accent", rgba("#2F7D70"), 0.58)\n\n    body = add_uv_sphere("Oyen_Body", (0.0, 0.0, 1.16), (0.73, 0.53, 0.72), orange)\n    parent_to_bone(body, rig, "spine")\n    belly = add_uv_sphere("Oyen_Belly", (0.0, -0.48, 1.15), (0.46, 0.10, 0.51), cream)\n    parent_to_bone(belly, rig, "spine")\n    chest_patch = add_uv_sphere("Oyen_Chest_Cream", (0.0, -0.42, 1.50), (0.33, 0.08, 0.29), cream)\n    parent_to_bone(chest_patch, rig, "chest")\n\n    head = add_uv_sphere("Oyen_Head", (0.0, -0.02, 2.02), (0.63, 0.53, 0.56), orange)\n    parent_to_bone(head, rig, "head")\n    cheek_l = add_uv_sphere("Oyen_Cheek_L", (-0.18, -0.48, 1.84), (0.25, 0.10, 0.17), cream)\n    cheek_r = add_uv_sphere("Oyen_Cheek_R", (0.18, -0.48, 1.84), (0.25, 0.10, 0.17), cream)\n    parent_to_bone(cheek_l, rig, "head")\n    parent_to_bone(cheek_r, rig, "head")\n\n'